#include <stdio.h>

unsigned long long factorial(int n) {
  if (n == 0 || n == 1) { // Əsas hal
    return 1;
  }
  return n * factorial(n - 1); // Rekursiv hal
}

int main() {
  int number = 5;
  printf("%d faktoriyal: %llu\n", number, factorial(number));
  return 0;
}
// Output:
// 5 faktoriyal: 120

#include <stdio.h>

int fibonacci(int n) {
  if (n <= 1) { // Əsas hal
    return n;
  }
  return fibonacci(n - 1) + fibonacci(n - 2); // Rekursiv hal
}

int main() {
  int number = 6;
  printf("Fibonacci(%d): %d\n", number, fibonacci(number));
  return 0;
}
// Output:
// Fibonacci(6): 8

#include <stdio.h>

int sum_of_digits(int num) {
  if (num == 0) { // Əsas hal
    return 0;
  }
  return (num % 10) + sum_of_digits(num / 10); // Rekursiv hal
}

int main() {
  int number = 123;
  printf("Reqemlerin cemi (%d): %d\n", number, sum_of_digits(number));
  return 0;
}
// Output:
// Reqemlerin cemi (123): 6

#include <stdio.h>

int bad_recursion(int n) {
  return n + bad_recursion(n - 1); // Səhv: Əsas hal yoxdur
}

int main() {
  printf("Neticə: %d\n", bad_recursion(5));
  return 0;
}
// Output: (Proqram çökəcək, çünki sonsuz rekursiya)

